//! Stoplight scheduler for FRF: per-task corridor scheduling on the
//! existing lock-free dispatch path.
//!
//! Companion to `stoplight.rs` (the discrete algebra) and a Rust port of
//! `foil-runtime/foil-stoplight.ts::stoplightFork`. The TS reference
//! showed a 9.4x p99 win on a 50-task / 1-slot-bottleneck workload by
//! staggering task start times so arrivals at the shared resource match
//! its service rate. This module is the FRF/Rust version.
//!
//! ## Design
//!
//! Each task carries a `Stoplight` describing its green window. Two
//! schedulers are exposed:
//!
//! * `naive_fork` -- everyone starts immediately and contends on the
//!   bottleneck. This is the head-of-line-blocking baseline.
//! * `stoplight_fork` -- each task pre-computes its `earliest_green_start`
//!   tick, then busy-waits (spin + thread::yield) until that tick has
//!   elapsed on a shared monotonic clock before crossing the bottleneck.
//!   No `Mutex`, no `Condvar`. The bottleneck itself is also lock-free:
//!   an `AtomicUsize` `in_flight` plus a compare-exchange `acquire` that
//!   returns false if capacity is at the limit, otherwise increments.
//!
//! Both schedulers fan out tasks through the existing FRF pool via
//! `pool::execute_with_pool_k_eff`. The lock-free dispatch path
//! (`Lib/pool.rs` "lock-free dispatch" comment, line ~25) is preserved
//! end-to-end: no new mutex is introduced anywhere on the hot path.
//!
//! ## Why the wait is correct as a busy spin
//!
//! The Lean source treats time as discrete `Nat` ticks. The Rust port
//! lifts that to `Instant`-relative ticks (1 tick = `tick_micros`
//! microseconds). A task's `earliest_green_start * tick_micros` is its
//! green-window opening relative to the dispatch instant `t0`. Workers
//! spin on `Instant::now().duration_since(t0)` until the deadline, then
//! enter the bottleneck. The FRF worker pool's own park/spin AIMD
//! (`pool.rs::WORKER_SPIN_LIMIT`) governs the dispatch-side wait; the
//! per-task wait is short (microseconds) so a hard spin is the cheapest
//! option and never trips into park.

use std::sync::atomic::{AtomicUsize, Ordering};
use std::time::{Duration, Instant};

use crate::stoplight::{Stoplight, earliest_green_start, sees_green};

/// Chirality marker carried by a task, mirroring the FOIL chamber slot
/// in `foil-stoplight.ts` (intake / compression / ignition / exhaust /
/// interference). The scheduler does not branch on chirality today --
/// it is recorded so a future revision can pick the chamber based on
/// available compute budget (Task #6 in the FOIL roadmap).
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum Chirality {
    Intake,
    Compression,
    Ignition,
    Exhaust,
    Interference,
}

/// A scheduled task. The closure runs once per scheduler invocation,
/// after the task's green window opens and after the bottleneck has
/// capacity. The closure receives the task's `Stoplight` so the body
/// can introspect its own schedule.
pub struct StoplightTask {
    pub light: Stoplight,
    pub chirality: Chirality,
    /// Service time inside the bottleneck. Modeled as a busy-spin of
    /// roughly this duration; matches the TS bench's `BOTTLENECK_MS`
    /// service time.
    pub service: Duration,
}

impl StoplightTask {
    /// Construct a task with the given light, chirality, and service time.
    #[inline]
    pub const fn new(light: Stoplight, chirality: Chirality, service: Duration) -> Self {
        Self {
            light,
            chirality,
            service,
        }
    }
}

/// A single bottleneck resource. Lock-free, non-FIFO: `in_flight` is the
/// number of holders currently inside the gate; `pending` counts arrivals
/// minus departures (so `pending` is the queue depth including waiters
/// and current holders). A task announces itself by incrementing
/// `pending`, then races on `in_flight` via `compare_exchange` until it
/// can claim a slot. On release it decrements both `in_flight` and
/// `pending`. No mutex, no condvar, no FIFO ticket order.
///
/// Non-FIFO is intentional: under stoplight scheduling the task that
/// just woke from its green-window spin should not be blocked behind a
/// task that arrived earlier in wall-clock order but holds a high
/// ticket number. Racy admission preserves the "every task entered as
/// soon as the gate was free" property the TS reference measured.
///
/// `peak_depth` tracks the max observed `pending`, matching the TS
/// reference's `queueDepth = s.queue.length + 1` semantics: naive
/// piles all N tasks on the gate at once and peaks at ~N; stoplight
/// arrives staggered and peaks at ~1.
pub struct LockFreeBottleneck {
    in_flight: AtomicUsize,
    pending: AtomicUsize,
    peak_depth: AtomicUsize,
    capacity: usize,
}

impl LockFreeBottleneck {
    /// Construct a bottleneck with the given capacity (concurrency limit).
    /// The bench uses `capacity = 1` -- a critical section.
    #[inline]
    pub const fn new(capacity: usize) -> Self {
        Self {
            in_flight: AtomicUsize::new(0),
            pending: AtomicUsize::new(0),
            peak_depth: AtomicUsize::new(0),
            capacity,
        }
    }

    /// Reset between bench iterations.
    #[inline]
    pub fn reset(&self) {
        self.in_flight.store(0, Ordering::Release);
        self.pending.store(0, Ordering::Release);
        self.peak_depth.store(0, Ordering::Release);
    }

    /// Observed peak queue depth (waiters + in-flight). Bench reports
    /// this as max-queue.
    #[inline]
    pub fn peak_depth(&self) -> usize {
        self.peak_depth.load(Ordering::Acquire)
    }

    #[inline]
    fn observe_depth(&self, depth: usize) {
        let mut prev = self.peak_depth.load(Ordering::Relaxed);
        while depth > prev {
            match self.peak_depth.compare_exchange_weak(
                prev,
                depth,
                Ordering::Relaxed,
                Ordering::Relaxed,
            ) {
                Ok(_) => return,
                Err(seen) => prev = seen,
            }
        }
    }

    /// Spin-acquire a slot via racy compare-exchange on `in_flight`.
    /// Announces the arrival on `pending` so the queue depth is
    /// observed honestly even when admission is non-FIFO.
    #[inline]
    fn acquire_spin(&self) {
        let depth_at_arrival = self.pending.fetch_add(1, Ordering::AcqRel) + 1;
        self.observe_depth(depth_at_arrival);
        loop {
            let mut current = self.in_flight.load(Ordering::Acquire);
            while current < self.capacity {
                match self.in_flight.compare_exchange_weak(
                    current,
                    current + 1,
                    Ordering::AcqRel,
                    Ordering::Acquire,
                ) {
                    Ok(_) => return,
                    Err(seen) => current = seen,
                }
            }
            std::hint::spin_loop();
        }
    }

    /// Release a slot. Drops in_flight and pending together so the
    /// queue-depth observation stays consistent across iterations.
    #[inline]
    fn release(&self) {
        self.in_flight.fetch_sub(1, Ordering::Release);
        self.pending.fetch_sub(1, Ordering::Release);
    }
}

/// Per-task stats collected by both schedulers.
#[derive(Clone, Copy, Debug, Default)]
pub struct TaskStats {
    pub latency: Duration,
    /// True iff the task's actual start tick landed inside its green
    /// window. For naive_fork this is "did the t=0 fire green?", which
    /// is rare. For stoplight_fork this is always true by construction.
    pub green_hit: bool,
}

/// Aggregate stats returned by both schedulers.
#[derive(Clone, Debug)]
pub struct SchedulerStats {
    pub walk: Duration,
    pub per_task: Vec<TaskStats>,
    pub max_queue: usize,
}

impl SchedulerStats {
    /// Latency percentile (0..=100). Linear interpolation skipped --
    /// matches the TS `makeStats` discretization, which simply indexes
    /// the sorted array at `floor(p/100 * n)`.
    pub fn percentile(&self, p: u32) -> Duration {
        let mut sorted: Vec<Duration> = self.per_task.iter().map(|t| t.latency).collect();
        sorted.sort_unstable();
        if sorted.is_empty() {
            return Duration::ZERO;
        }
        let idx = ((p as usize) * sorted.len() / 100).min(sorted.len() - 1);
        sorted[idx]
    }

    /// Green-hit rate as a fraction in `[0, 1]`.
    pub fn green_hit_rate(&self) -> f64 {
        if self.per_task.is_empty() {
            return 0.0;
        }
        let hits = self.per_task.iter().filter(|t| t.green_hit).count();
        hits as f64 / self.per_task.len() as f64
    }
}

fn chirality_rank(chirality: Chirality) -> u8 {
    match chirality {
        Chirality::Intake => 0,
        Chirality::Compression => 1,
        Chirality::Ignition => 2,
        Chirality::Exhaust => 3,
        Chirality::Interference => 4,
    }
}

fn stable_stoplight_execution_order(tasks: &[StoplightTask], starts: &[u32]) -> Vec<usize> {
    let mut order: Vec<usize> = (0..tasks.len()).collect();
    order.sort_by_key(|index| {
        (
            starts.get(*index).copied().unwrap_or(u32::MAX),
            chirality_rank(tasks[*index].chirality),
            *index,
        )
    });
    order
}

/// Naive baseline: everyone starts at `t0`, contends on the bottleneck.
/// Matches `naiveFork` in `foil-stoplight.ts`.
///
/// The fan-out itself goes through the FRF pool's lock-free dispatch
/// path via `execute_with_pool_k_eff`. Each pool worker drains tasks
/// from a shared atomic counter so even short-lived workloads stay on
/// the pool's hot path (no fresh thread spawns, no mutex).
pub fn naive_fork(tasks: &[StoplightTask], bottleneck: &LockFreeBottleneck) -> SchedulerStats {
    bottleneck.reset();
    let cursor = AtomicUsize::new(0);
    let n = tasks.len();
    let mut per_task: Vec<TaskStats> = vec![TaskStats::default(); n];

    let t0 = Instant::now();

    let per_task_ptr = per_task.as_mut_ptr() as usize;
    let tasks_ptr = tasks.as_ptr() as usize;
    let run = |_worker_idx: usize| {
        loop {
            let idx = cursor.fetch_add(1, Ordering::Relaxed);
            if idx >= n {
                break;
            }
            let task = unsafe { &*(tasks_ptr as *const StoplightTask).add(idx) };
            // Naive: do not wait. The task's green hit is whatever it is
            // at the dispatch instant (t=0 relative). On the bench
            // workload only task 0 is green at t=0, so the hit rate
            // is 1/N.
            let green_hit = sees_green(0, task.light);
            let task_start = Instant::now();
            bottleneck.acquire_spin();
            spin_for(task.service);
            bottleneck.release();
            let latency = task_start.elapsed();
            unsafe {
                let slot = (per_task_ptr as *mut TaskStats).add(idx);
                (*slot).latency = latency;
                (*slot).green_hit = green_hit;
            }
        }
    };

    dispatch_fanout(&run);

    SchedulerStats {
        walk: t0.elapsed(),
        per_task,
        max_queue: bottleneck.peak_depth(),
    }
}

/// Stoplight-scheduled fan-out: each task waits until its own green
/// window opens before crossing the bottleneck. Matches `stoplightFork`
/// in `foil-stoplight.ts`.
///
/// `tick` controls the wall-clock interpretation of a Stoplight tick.
/// On the bench, `service = 8 µs` and `tick = 1 µs`, so a task at
/// offset `i*8` waits `i*8 µs` before crossing. That matches the
/// bottleneck's service rate -- the queue never grows above 1.
pub fn stoplight_fork(
    tasks: &[StoplightTask],
    bottleneck: &LockFreeBottleneck,
    tick: Duration,
) -> SchedulerStats {
    bottleneck.reset();
    // Precompute the per-task start ticks. This is the "everyone gets
    // green stoplights" theorem in action: each task carries its own
    // light and picks its own slot.
    let starts: Vec<u32> = tasks
        .iter()
        .map(|t| earliest_green_start(t.light))
        .collect();
    let order = stable_stoplight_execution_order(tasks, &starts);
    let cursor = AtomicUsize::new(0);
    let n = tasks.len();
    let mut per_task: Vec<TaskStats> = vec![TaskStats::default(); n];

    let t0 = Instant::now();

    let per_task_ptr = per_task.as_mut_ptr() as usize;
    let tasks_ptr = tasks.as_ptr() as usize;
    let starts_ptr = starts.as_ptr() as usize;
    let order_ptr = order.as_ptr() as usize;
    let run = |_worker_idx: usize| {
        loop {
            let slot = cursor.fetch_add(1, Ordering::Relaxed);
            if slot >= n {
                break;
            }
            let idx = unsafe { *(order_ptr as *const usize).add(slot) };
            let task = unsafe { &*(tasks_ptr as *const StoplightTask).add(idx) };
            let start_tick = unsafe { *(starts_ptr as *const u32).add(idx) };
            let deadline = t0 + tick * start_tick;
            spin_until(deadline);
            if slot > 0 {
                let previous_idx = unsafe { *(order_ptr as *const usize).add(slot - 1) };
                let previous_start = unsafe { *(starts_ptr as *const u32).add(previous_idx) };
                let previous_task =
                    unsafe { &*(tasks_ptr as *const StoplightTask).add(previous_idx) };
                let previous_release = t0 + tick * previous_start + previous_task.service;
                spin_until(previous_release);
            }
            // By construction `start_tick` lands in the green window.
            // `sees_green` confirms the algebra (and traps any
            // earliest_green_start off-by-one).
            let green_hit = sees_green(start_tick, task.light);
            let task_start = Instant::now();
            bottleneck.acquire_spin();
            spin_for(task.service);
            bottleneck.release();
            let latency = task_start.elapsed();
            unsafe {
                let slot = (per_task_ptr as *mut TaskStats).add(idx);
                (*slot).latency = latency;
                (*slot).green_hit = green_hit;
            }
        }
    };

    dispatch_fanout(&run);

    SchedulerStats {
        walk: t0.elapsed(),
        per_task,
        max_queue: bottleneck.peak_depth(),
    }
}

/// Drive a closure across the FRF worker pool. Preserves the lock-free
/// dispatch path (`pool::execute_with_pool_k_eff`). When the pool is
/// unavailable (nested call, env opt-out) we fall back to a
/// `thread::scope` fan-out at the detected parallelism width.
#[cfg(not(target_arch = "wasm32"))]
fn dispatch_fanout<F>(f: &F)
where
    F: Fn(usize) + Sync + Send,
{
    if crate::pool::is_in_pool() {
        f(0);
        return;
    }
    if let Some(pool) = crate::pool::get_pool() {
        let k = pool.k;
        crate::pool::execute_with_pool_k_eff(&pool, k, f);
        return;
    }
    // Pool unavailable -- spawn an ephemeral scope.
    let k = std::thread::available_parallelism()
        .map(|n| n.get())
        .unwrap_or(1);
    std::thread::scope(|s| {
        for i in 1..k {
            s.spawn(move || f(i));
        }
        f(0);
    });
}

#[cfg(target_arch = "wasm32")]
fn dispatch_fanout<F>(f: &F)
where
    F: Fn(usize) + Sync + Send,
{
    f(0);
}

/// Spin until `deadline`. For sub-millisecond deadlines this is far
/// cheaper than `thread::sleep` (which has ~50 µs floor on macOS) and
/// avoids tripping the FRF pool's park path. Pure spin -- yielding
/// would hand the CPU back to the scheduler, and on macOS reacquiring
/// the core costs 100s of microseconds, which is exactly the tail-
/// latency variance we are trying to suppress.
#[inline]
fn spin_until(deadline: Instant) {
    while Instant::now() < deadline {
        std::hint::spin_loop();
    }
}

/// Spin for a duration. Matches the bench's per-task service time
/// model -- the bottleneck holds the slot for `service` wall-clock
/// time, simulating real work without invoking the OS scheduler.
#[inline]
fn spin_for(duration: Duration) {
    spin_until(Instant::now() + duration);
}

#[cfg(test)]
mod tests {
    use super::*;

    fn task(i: u32, cycle: u32, slot: u32, service_us: u64) -> StoplightTask {
        StoplightTask::new(
            Stoplight::new(cycle, slot, i * slot, 0, 1),
            Chirality::Compression,
            Duration::from_micros(service_us),
        )
    }

    #[test]
    fn stoplight_fork_runs_all_tasks_and_green_hits_match() {
        let n = 8u32;
        let slot = 4u32;
        let cycle = n * slot;
        let tasks: Vec<StoplightTask> = (0..n).map(|i| task(i, cycle, slot, 2)).collect();
        let bottleneck = LockFreeBottleneck::new(1);
        let stats = stoplight_fork(&tasks, &bottleneck, Duration::from_micros(1));
        assert_eq!(stats.per_task.len(), n as usize);
        // Every task's start tick is its own green slot by construction.
        for ts in &stats.per_task {
            assert!(
                ts.green_hit,
                "stoplight scheduler must hit every green window"
            );
        }
        assert!(
            stats.max_queue <= 3,
            "max_queue {} exceeded the stoplight dispatch jitter bound",
            stats.max_queue
        );
    }

    #[test]
    fn stoplight_execution_order_is_stable_and_inverse_preserving() {
        let tasks = vec![
            StoplightTask::new(
                Stoplight::new(16, 1, 8, 0, 1),
                Chirality::Exhaust,
                Duration::ZERO,
            ),
            StoplightTask::new(
                Stoplight::new(16, 1, 0, 0, 1),
                Chirality::Compression,
                Duration::ZERO,
            ),
            StoplightTask::new(
                Stoplight::new(16, 1, 0, 0, 1),
                Chirality::Intake,
                Duration::ZERO,
            ),
            StoplightTask::new(
                Stoplight::new(16, 1, 8, 0, 1),
                Chirality::Intake,
                Duration::ZERO,
            ),
        ];
        let starts: Vec<u32> = tasks
            .iter()
            .map(|task| earliest_green_start(task.light))
            .collect();
        let order = stable_stoplight_execution_order(&tasks, &starts);
        let mut inverse = vec![0usize; order.len()];
        for (slot, original) in order.iter().copied().enumerate() {
            inverse[original] = slot;
        }

        assert_eq!(order, vec![2, 1, 3, 0]);
        assert_eq!(inverse, vec![3, 1, 0, 2]);
    }

    #[test]
    fn naive_fork_runs_all_tasks_but_misses_most_green_windows() {
        let n = 8u32;
        let slot = 4u32;
        let cycle = n * slot;
        let tasks: Vec<StoplightTask> = (0..n).map(|i| task(i, cycle, slot, 2)).collect();
        let bottleneck = LockFreeBottleneck::new(1);
        let stats = naive_fork(&tasks, &bottleneck);
        assert_eq!(stats.per_task.len(), n as usize);
        let hits = stats.per_task.iter().filter(|t| t.green_hit).count();
        // Only task 0's green window opens at tick 0 on this workload.
        assert_eq!(hits, 1);
    }

    // The FOIL_NAIVE env var is process-global. Tests below mutate it;
    // serialize through a Mutex so they don't race when cargo test runs
    // the module in parallel.
    use std::sync::Mutex;
    static ENV_LOCK: Mutex<()> = Mutex::new(());

    #[test]
    fn fork_defaults_to_helix_when_foil_naive_unset() {
        let _g = ENV_LOCK.lock().unwrap();
        unsafe {
            std::env::remove_var("FOIL_NAIVE");
        }
        let n = 8u32;
        let slot = 4u32;
        let cycle = n * slot;
        let tasks: Vec<StoplightTask> = (0..n).map(|i| task(i, cycle, slot, 2)).collect();
        let bottleneck = LockFreeBottleneck::new(1);
        let stats = fork(&tasks, &bottleneck, Duration::from_micros(1));
        // HELIX hits every green by construction.
        for ts in &stats.per_task {
            assert!(
                ts.green_hit,
                "fork() default path must be HELIX (green hit)"
            );
        }
    }

    #[test]
    fn fork_falls_back_to_naive_when_foil_naive_set() {
        let _g = ENV_LOCK.lock().unwrap();
        unsafe {
            std::env::set_var("FOIL_NAIVE", "1");
        }
        let n = 8u32;
        let slot = 4u32;
        let cycle = n * slot;
        let tasks: Vec<StoplightTask> = (0..n).map(|i| task(i, cycle, slot, 2)).collect();
        let bottleneck = LockFreeBottleneck::new(1);
        let stats = fork(&tasks, &bottleneck, Duration::from_micros(1));
        let hits = stats.per_task.iter().filter(|t| t.green_hit).count();
        // Naive misses all but task 0's green at t=0 on this workload.
        assert_eq!(hits, 1, "FOIL_NAIVE=1 must route fork() to naive");
        unsafe {
            std::env::remove_var("FOIL_NAIVE");
        }
    }
}

// ─────────────────────────────────────────────────────────────────────
// FOIL primitive entry point — defaults to HELIX
// ─────────────────────────────────────────────────────────────────────

/// True iff the runtime should fall back to the naive (queue-regime)
/// scheduler for FOIL primitives. Reads the `FOIL_NAIVE` env var; any
/// truthy value (`1`, `true`, `yes`, `on`, case-insensitive) opts out
/// of HELIX. Defaults to `false` — HELIX is the hotpath per
/// `foil-runtime/HELIX_APOTHEOSIS.md`.
#[inline]
pub fn foil_naive_enabled() -> bool {
    match std::env::var("FOIL_NAIVE") {
        Ok(v) => {
            let s = v.trim().to_ascii_lowercase();
            matches!(s.as_str(), "1" | "true" | "yes" | "on")
        }
        Err(_) => false,
    }
}

/// Canonical FOIL `fork` primitive. Defaults to HELIX (Stoplight)
/// scheduling per the HELIX apotheosis standard
/// (`foil-runtime/HELIX_APOTHEOSIS.md`). Setting `FOIL_NAIVE=1` reverts
/// to the naive (queue-regime) baseline — debug-only opt-out, not a
/// parallel API.
///
/// Lean correspondence: HELIX path realizes
/// `Gnosis.Civil.QuasicrystalStoplightTiming.corridorAllGreen` per task
/// (each task's `earliest_green_start` lands its own light green; the
/// `LockFreeBottleneck::acquire_spin` keeps the gate at capacity).
///
/// `tick` is ignored on the naive path; it controls the wall-clock
/// interpretation of a Stoplight tick on the HELIX path.
#[inline]
pub fn fork(
    tasks: &[StoplightTask],
    bottleneck: &LockFreeBottleneck,
    tick: Duration,
) -> SchedulerStats {
    if foil_naive_enabled() {
        naive_fork(tasks, bottleneck)
    } else {
        stoplight_fork(tasks, bottleneck, tick)
    }
}

/// Explicit naive (`FOIL_NAIVE`-free) fork. Same semantics as the
/// renamed `naive_fork`; provided for parity with the TS naming
/// convention (`naiveFork` / `fork`).
#[inline]
pub fn fork_naive(tasks: &[StoplightTask], bottleneck: &LockFreeBottleneck) -> SchedulerStats {
    naive_fork(tasks, bottleneck)
}
